#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int a[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }
    int xor = 0;
    for (int i = 0; i < n; i++) {
        xor ^= a[i];
    }
    int count = 0;
    for (int i = 0; i < n; i++) {
        if ((xor ^ a[i]) != 0) {
            count++;
        }
    }
    printf("%d\n", count);
    return 0;
}

