const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let a;
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        a = input.split(' ').map(Number);
        let xor = 0;
        for (let i = 0; i < n; i++) {
            xor ^= a[i];
        }
        let count = 0;
        for (let i = 0; i < n; i++) {
            if ((xor ^ a[i]) != 0) {
                count++;
            }
        }
        console.log(count);
        rl.close();
    }
});

